mapper.select:
/*AdminBoard_SQL.selectAdminNoticeTotalCount*/ SELECT COUNT(*) FROM TB_NOTICE_INFO WHERE 1=1 AND NOTICE_DEL_YN = 'N'
AND NOTICE_TITLE LIKE CONCAT('%', #{searchTxt}, '%')
AND REG_ID LIKE CONCAT('%', #{searchTxt}, '%')

/*AdminBoard_SQL.selectAdminNotice*/ SELECT A.NOTICE_ID , A.NOTICE_TITLE , A.NOTICE_EFFECT_GB , A.NOTICE_CN , A.NOTICE_FIX_YN , A.NOTICE_LIMIT_YN , TO_CHAR(A.NOTICE_STR_DT, 'YYYY-MM-DD HH24:MI:SS') AS NOTICE_STR_DT , TO_CHAR(A.NOTICE_END_DT, 'YYYY-MM-DD HH24:MI:SS') AS NOTICE_END_DT , A.NOTICE_FINISH_YN , A.NOTICE_DEL_YN , A.NOTICE_POP_YN , A.REG_ID , TO_CHAR(A.REG_DT, 'YYYY-MM-DD HH24:MI:SS') AS REG_DT , A.UPD_ID , A.UPD_DT FROM TB_NOTICE_INFO A WHERE 1=1 AND A.NOTICE_DEL_YN = 'N' AND ( A.NOTICE_LIMIT_YN = 'N' OR ( A.NOTICE_LIMIT_YN = 'Y' AND CURRENT_TIMESTAMP >= A.NOTICE_STR_DT AND CURRENT_TIMESTAMP <= A.NOTICE_END_DT ) )
AND A.NOTICE_TITLE LIKE CONCAT('%', #{searchTxt}, '%')
AND A.REG_ID LIKE CONCAT('%', #{searchTxt}, '%')
ORDER BY CASE WHEN A.NOTICE_FIX_YN = 'Y' THEN 0 ELSE 1 END, A.REG_DT DESC LIMIT #{perPage} OFFSET #{startRow}

mapper.insert:
		/*AdminBoard_SQL.insertAdminNotice*/
	    INSERT INTO TB_NOTICE_INFO (
	        NOTICE_ID
	      , NOTICE_TITLE
	      , NOTICE_EFFECT_GB
	      , NOTICE_CN
	      , NOTICE_FIX_YN
	      , NOTICE_LIMIT_YN
	      , NOTICE_STR_DT
	      , NOTICE_END_DT
	      , NOTICE_FINISH_YN
	      , NOTICE_DEL_YN
	      , NOTICE_POP_YN
	      , REG_ID
	      , REG_DT
	      , UPD_ID
	      , UPD_DT
	    ) VALUES (
            #{noticeId} 
          , #{noticeTitle}
          , #{noticeEffectGb}
          , #{noticeCn}
          , #{noticeFixYn}
          , #{noticeLimitYn}
		  , NULLIF(#{noticeStrDt}, '')::timestamp
		  , NULLIF(#{noticeEndDt}, '')::timestamp
       	  , 'N'
       	  , 'N'
       	  , #{noticePopYn}
          , #{regId}
          , NOW()
          , #{updId}
          , NOW()
	    )

		/*AdminBoard_SQL.insertAdminFile*/
    	INSERT INTO TB_FILE_INFO (
    		FILE_ID
      	  , FILE_ORG_NM
          , FILE_NM
          , FILE_PATH
       	  , FILE_SIZE
          , FILE_EXT
          , REF_TYPE
          , REF_ID
          , FILE_THUMB_NM
          , FILE_THUMB_PATH
          , REG_ID
          , REG_DT
          , UPD_ID
          , UPD_DT
	    ) VALUES (
            #{fileId}
          , #{fileOrgNm}
	      , #{fileNm}
	      , #{filePath}
	      , #{fileSize}
	      , #{fileExt}
	      , #{refType}
	      , #{refId}
	      , #{fileThumbNm}	      
	      , #{fileThumbPath}	      
	      , #{regId}
	      , NOW()
	      , #{updId}
	      , NOW()
	    )

mapper.select:
		/*AdminBoard_SQL.countNoticeFiles*/
  	SELECT COUNT(*)
        FROM TB_FILE_INFO
       WHERE 1=1
       	 AND REF_TYPE = 'NOTICE'
           AND REF_ID = #{noticeId}

mapper.update:
    	/*AdminBoard_SQL.updateAdminNotice*/
        UPDATE TB_NOTICE_INFO
             SET NOTICE_TITLE    		= #{noticeTitle}
	             , NOTICE_EFFECT_GB  	= #{noticeEffectGb}
	             , NOTICE_CN       		= #{noticeCn}
	             , NOTICE_FIX_YN   		= #{noticeFixYn}
	             , NOTICE_POP_YN   	= #{noticePopYn}
	             , NOTICE_LIMIT_YN 	= #{noticeLimitYn}
	             , NOTICE_STR_DT   	= NULLIF(#{noticeStrDt}, '')::timestamp
	             , NOTICE_END_DT   	= NULLIF(#{noticeEndDt}, '')::timestamp
	             , UPD_ID          		= #{updId}
	             , UPD_DT          		= NOW()
         WHERE 1=1
         	 AND NOTICE_ID       	= #{noticeId}

mapper.delete:
	/*AdminBoard_SQL.deleteAdminNoticeFile*/
    DELETE FROM TB_FILE_INFO
    WHERE 1=1
    	AND REF_TYPE = 'NOTICE'
        AND REF_ID = #{noticeId}
        AND FILE_ID IN
	
    		#{deleteId}

