mapper.update:
    	/*AdminBoard_SQL.deleteAdminNotice*/
        UPDATE TB_NOTICE_INFO
             SET NOTICE_DEL_YN 	= 'Y'
	             , UPD_ID          		= #{updId}
	             , UPD_DT          		= NOW()
         WHERE 1=1
         	 AND NOTICE_ID       	= #{noticeId}

